code.C:
#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, B;
        scanf("%d %d", &N, &B);
        printf("%d\n", (int)ceil((double)N / (B - 1 + (double)1 / (B - 1))));
    }
    return 0;
}

