code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int B = sc.nextInt();
            System.out.println((int)Math.ceil((double)N / (B - 1 + (double)1 / (B - 1))));
        }
    }
}

